'use client';

import * as React from "react";
import { motion, AnimatePresence } from "framer-motion";
import { X, Moon, Sun, Globe, Bell, Shield, ChevronRight } from "lucide-react";

interface SettingsModalProps {
  isOpen: boolean;
  onClose: () => void;
}

// 设置项组件
function SettingItem({ 
  icon, 
  label, 
  description, 
  children,
  onClick 
}: { 
  icon: React.ReactNode; 
  label: string; 
  description?: string;
  children?: React.ReactNode;
  onClick?: () => void;
}) {
  return (
    <div 
      className={`flex items-center justify-between p-4 rounded-xl bg-white/5 border border-white/10 ${onClick ? 'cursor-pointer hover:bg-white/10' : ''} transition-colors`}
      onClick={onClick}
    >
      <div className="flex items-center gap-4">
        <div className="w-10 h-10 rounded-xl bg-[#00f5ff]/10 flex items-center justify-center text-[#00f5ff]">
          {icon}
        </div>
        <div>
          <p className="text-white font-medium">{label}</p>
          {description && <p className="text-sm text-white/40">{description}</p>}
        </div>
      </div>
      {children}
    </div>
  );
}

// 开关组件
function Toggle({ checked, onChange }: { checked: boolean; onChange: (checked: boolean) => void }) {
  return (
    <button
      className={`relative w-12 h-6 rounded-full transition-colors ${checked ? 'bg-[#00f5ff]' : 'bg-white/20'}`}
      onClick={() => onChange(!checked)}
    >
      <motion.div
        className="absolute top-1 left-1 w-4 h-4 rounded-full bg-white"
        animate={{ x: checked ? 24 : 0 }}
        transition={{ type: "spring", stiffness: 500, damping: 30 }}
      />
    </button>
  );
}

export function SettingsModal({ isOpen, onClose }: SettingsModalProps) {
  const [darkMode, setDarkMode] = React.useState(true);
  const [notifications, setNotifications] = React.useState(true);
  const [language, setLanguage] = React.useState<'zh' | 'en'>('zh');

  return (
    <AnimatePresence>
      {isOpen && (
        <>
          {/* 遮罩 */}
          <motion.div
            className="fixed inset-0 bg-black/80 backdrop-blur-sm z-50"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            onClick={onClose}
          />
          
          {/* 弹窗 */}
          <motion.div
            className="fixed left-1/2 top-1/2 -translate-x-1/2 -translate-y-1/2 z-50 w-full max-w-md"
            initial={{ opacity: 0, scale: 0.95, y: 20 }}
            animate={{ opacity: 1, scale: 1, y: 0 }}
            exit={{ opacity: 0, scale: 0.95, y: 20 }}
            transition={{ duration: 0.2 }}
          >
            <div className="bg-[rgba(15,15,25,0.98)] backdrop-blur-xl rounded-3xl border border-[#00f5ff]/20 shadow-[0_0_60px_rgba(0,245,255,0.15)] overflow-hidden max-h-[80vh] flex flex-col">
              {/* 头部 */}
              <div className="relative p-6 border-b border-white/5 flex-shrink-0">
                <button
                  onClick={onClose}
                  className="absolute right-4 top-1/2 -translate-y-1/2 p-2 rounded-xl text-white/40 hover:text-white hover:bg-white/5 transition-colors"
                >
                  <X size={20} />
                </button>
                
                <div className="text-center">
                  <h2 className="text-xl font-bold text-white mb-1">设置</h2>
                  <p className="text-sm text-white/50">自定义您的体验</p>
                </div>
              </div>

              {/* 设置列表 */}
              <div className="p-4 space-y-3 overflow-y-auto">
                {/* 主题设置 */}
                <SettingItem
                  icon={<Moon size={20} />}
                  label="深色模式"
                  description="切换浅色/深色主题"
                >
                  <Toggle checked={darkMode} onChange={setDarkMode} />
                </SettingItem>

                {/* 通知设置 */}
                <SettingItem
                  icon={<Bell size={20} />}
                  label="通知"
                  description="接收收益和奖励提醒"
                >
                  <Toggle checked={notifications} onChange={setNotifications} />
                </SettingItem>

                {/* 语言设置 */}
                <SettingItem
                  icon={<Globe size={20} />}
                  label="语言"
                  description={language === 'zh' ? '简体中文' : 'English'}
                  onClick={() => setLanguage(language === 'zh' ? 'en' : 'zh')}
                >
                  <ChevronRight size={20} className="text-white/40" />
                </SettingItem>

                {/* 安全设置 */}
                <div className="pt-4 border-t border-white/5">
                  <p className="text-xs text-white/40 mb-3 px-1">安全</p>
                  <div className="space-y-3">
                    <SettingItem
                      icon={<Shield size={20} />}
                      label="导出助记词"
                      onClick={() => alert('助记词导出功能开发中...')}
                    >
                      <ChevronRight size={20} className="text-white/40" />
                    </SettingItem>
                  </div>
                </div>

                {/* 关于 */}
                <div className="pt-4 border-t border-white/5">
                  <p className="text-xs text-white/40 mb-3 px-1">关于</p>
                  <div className="p-4 rounded-xl bg-white/5 border border-white/10 text-center">
                    <p className="text-white font-medium mb-1">赤道ETR DeFi Platform</p>
                    <p className="text-sm text-white/40">版本 v0.1.0</p>
                  </div>
                </div>
              </div>
            </div>
          </motion.div>
        </>
      )}
    </AnimatePresence>
  );
}

export default SettingsModal;
